INSERT INTO skills (id, slug, name, description, description_it, max_level, type1, type2) VALUES
  (1, 'dragon_resistance', 'Dragon Resistance', 'Increases dragon resistance. Also improves defense at higher levels.', 'Incrementa la resistenza al drago. Fai salire di livello per aumentare anche la difesa.', 3, 'armor', 'utility'),
  (2, 'spread_power_shots', 'Spread/Power Shots', 'Increases the attack of the bowgun''s Spread Ammo and the bow''s Power Shots and Quick Shots.', 'Aumenta l''attacco dei proiettili ventaglio della balestra e del tiro potente e tiro rapido dell''arco.', 1, 'weapon', 'utility'),
