  (5, 'blast_functionality', 'Blast Functionality', 'Allows you to apply blast coatings.', 'Consente di applicare il rivestimento scoppio.', 1, 'weapon', 'utility'),
  (6, 'normal_shots', 'Normal Shots', 'Increases the attack power of Normal Ammo, normal arrows, and Flying Swallow Shot.', 'Incrementa la potenza d''attacco dei proiettili normali, delle frecce normali e del tiro esotico volante.', 1, 'weapon', 'utility'),
