  (11, 'fulgur_anjanaths_will', 'Fulgur Anjanath''s Will', NULL, NULL, 2, 'set', 'utility'),
  (12, 'poison_attack', 'Poison Attack', 'Increases the rate of poison buildup. (Poison buildup has a maximum limit.)', 'Incrementa l''accumulo del veleno. (L''accumulo di veleno ha un limite massimo.)', 3, 'weapon', 'utility'),
  (13, 'coalescence', 'Coalescence', 'Temporarily increases elemental attack power and status effects after recovering from blights or abnormal status.', 'Aumenta temporaneamente l''attacco elementale e gli effetti di stato se guarisci da malus o alterazioni.', 3, 'armor', 'utility'),
