  (39, 'slicked_blade', 'Slicked Blade', 'Temporarily increases affinity when wet or when inflicted with bubbleblight. (Wet and bubbleblight effects stack.)', 'Aumenta temporaneamente l''affinità se bagnati o afflitti da malus da bolle (gli effetti si accumulano).', 3, 'weapon', 'utility'),
  (40, 'blast_attack', 'Blast Attack', 'Increases the rate of blast buildup. (Blast buildup has a maximum limit.)', 'Incrementa l''accumulo dello scoppio. (L''accumulo di scoppio ha un limite massimo.)', 3, 'weapon', 'utility'),
  (41, 'dragon_attack', 'Dragon Attack', 'Increases dragon element attack power. (Elemental attack power has a maximum limit.)', 'Incrementa la potenza degli attacchi basati sull''elemento drago. (Non va oltre il limite massimo.)', 3, 'weapon', 'utility'),
  (42, 'cliffhanger', 'Cliffhanger', 'Decreases stamina depletion when climbing on vines.', 'Riduce il consumo di resistenza quando sali sui rampicanti.', 1, 'armor', 'utility'),
